1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const FIRST_INSURANCE_RATE = 0.1;
28	const PROCESSING_FEE = 5;
29	
30	const COMPONENT_TYPES = ["rune", "moonstone"];
31	const COMPONENT_BLOCK_SIZE = 3;
32	const COMPONENT_BLOCK_PREMIUM = 60;
33	
34	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
35	
36	const typeBasePremium = (type: string, count: number): number =>
37	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
38	    ? COMPONENT_BLOCK_PREMIUM
39	    : count * BASE_PREMIUM[type];
40	
41	const CURSE_RATE = 0.5;
42	
43	const itemSurcharges = (items: Item[]): number =>
44	  items.reduce(
45	    (sum, item) => sum + (item.cursed ? CURSE_RATE * BASE_PREMIUM[item.type] : 0),
46	    0,
47	  );
48	
49	const countByType = (items: Item[]): Map<string, number> => {
50	  const counts = new Map<string, number>();
51	  for (const item of items) {
52	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
53	  }
54	  return counts;
55	};
56	
57	const policyBasePremium = (items: Item[]): number =>
58	  [...countByType(items)].reduce(
59	    (total, [type, count]) => total + typeBasePremium(type, count),
60	    0,
61	  );
62	
63	const quotePremium = (step: QuoteStep): number => {
64	  const policyBase = policyBasePremium(step.items);
65	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
66	  return Math.ceil(
67	    policyBase + itemSurcharges(step.items) + firstInsurance + PROCESSING_FEE,
68	  );
69	};
70	
71	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
72	  return {
73	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
74	  };
75	};
